entity design_1_axi_smc_1_proc_sys_reset is
  port (
    interconnect_aresetn : out STD_LOGIC_VECTOR ( 0 to 0 );
    aclk : in STD_LOGIC;
    aresetn : in STD_LOGIC
  );
end design_1_axi_smc_1_proc_sys_reset;

architecture STRUCTURE of design_1_axi_smc_1_proc_sys_reset is
  signal SEQ_n_0 : STD_LOGIC;
  signal lpf_int : STD_LOGIC;
  attribute BOX_TYPE : string;
  attribute BOX_TYPE of \ACTIVE_LOW_BSR_OUT_DFF[0].FDRE_BSR_N\ : label is "PRIMITIVE";
begin
\ACTIVE_LOW_BSR_OUT_DFF[0].FDRE_BSR_N\: unisim.vcomponents.FDRE
    generic map(
      INIT => '0',
      IS_C_INVERTED => '0',
      IS_D_INVERTED => '0',
      IS_R_INVERTED => '0'
    )
        port map (
      C => aclk,
      CE => '1',
      D => SEQ_n_0,
      Q => interconnect_aresetn(0),
      R => '0'
    );
EXT_LPF: entity work.design_1_axi_smc_1_lpf
     port map (
      aclk => aclk,
      aresetn => aresetn,
      lpf_int => lpf_int
    );
SEQ: entity work.design_1_axi_smc_1_sequence_psr
     port map (
      aclk => aclk,
      bsr_reg_0 => SEQ_n_0,
      lpf_int => lpf_int
    );
end STRUCTURE;
